[metadata] {"type": "text", "file": {"filePath": "/workspace/kafka--0753c489/connect/runtime/src/main/java/org/apache/kafka/connect/runtime/Connect.java", "content": "/*\n * Licensed to the Apache Software Foundation (ASF) under one or more\n * contributor license agreements. See the NOTICE file distributed with\n * this work for additional information regarding copyright ownership.\n * The ASF licenses this file to You under the Apache License, Version 2.0\n * (the \"License\"); you may not use this file except in compliance with\n * the License. You may obtain a copy of the License at\n *\n *    http://www.apache.org/licenses/LICENSE-2.0\n *\n * Unless required by applicable law or agreed to in writing, software\n * distributed under the License is distributed on an \"AS IS\" BASIS,\n * WITHOUT WARRANTIES OR CONDITIONS OF ANY KIND, either express or implied.\n * See the License for the specific language governing permissions and\n * limitations under the License.\n */\npackage org.apache.kafka.connect.runtime;\n\nimport org.apache.kafka.common.utils.Exit;\nimport org.apache.kafka.connect.runtime.distributed.DistributedHerder;\nimport org.apache.kafka.connect.runtime.rest.ConnectRestServer;\nimport org.apache.kafka.connect.runtime.rest.RestServer;\n\nimport org.slf4j.Logger;\nimport org.slf4j.LoggerFactory;\n\nimport java.util.concurrent.CountDownLatch;\nimport java.util.concurrent.Future;\nimport java.util.concurrent.atomic.AtomicBoolean;\n\n/**\n * This class ties together all the components of a Kafka Connect process (herder, worker,\n * storage, command interface), managing their lifecycle.\n */\npublic class Connect<H extends Herder> {\n    private static final Logger log = LoggerFactory.getLogger(Connect.class);\n\n    private final H herder;\n    private Future<?> herderTask;\n    private final ConnectRestServer rest;\n    private final CountDownLatch startLatch = new CountDownLatch(1);\n    private final CountDownLatch stopLatch = new CountDownLatch(1);\n    private final AtomicBoolean shutdown = new AtomicBoolean(false);\n    private final ShutdownHook shutdownHook;\n\n    public Connect(H herder, ConnectRestServer rest) {\n        log.debug(\"Kafka Connect instance created\");\n        this.herder = herder;\n        this.rest = rest;\n        shutdownHook = new ShutdownHook();\n    }\n\n    /**\n     * Track task status which have been submitted to work thread.\n     * @return {@link DistributedHerder#herderTask} to track status or null if the herder type doesn't have a separate work thread\n     */\n    public Future<?> herderTask() {\n        return this.herderTask;\n    }\n\n    public H herder() {\n        return herder;\n    }\n\n    public void start() {\n        try {\n            log.info(\"Kafka Connect starting\");\n            Exit.addShutdownHook(\"connect-shutdown-hook\", shutdownHook);\n\n            herder.start();\n            rest.initializeResources(herder);\n\n            if (herder instanceof DistributedHerder) {\n                herderTask = ((DistributedHerder) herder).herderTask();\n            }\n\n            log.info(\"Kafka Connect started\");\n        } finally {\n            startLatch.countDown();\n        }\n    }\n\n    public void stop() {\n        try {\n            boolean wasShuttingDown = shutdown.getAndSet(true);\n            if (!wasShuttingDown) {\n                log.info(\"Kafka Connect stopping\");\n\n                rest.stop();\n                herder.stop();\n\n                log.info(\"Kafka Connect stopped\");\n            }\n        } finally {\n            stopLatch.countDown();\n        }\n    }\n\n    public void awaitStop() {\n        try {\n            stopLatch.await();\n        } catch (InterruptedException e) {\n            log.error(\"Interrupted waiting for Kafka Connect to shutdown\");\n        }\n    }\n\n    // Visible for testing\n    public RestServer rest() {\n        return rest;\n    }\n\n    private class ShutdownHook extends Thread {\n        @Override\n        public void run() {\n            try {\n                startLatch.await();\n                Connect.this.stop();\n            } catch (InterruptedException e) {\n                log.error(\"Interrupted in shutdown hook while waiting for Kafka Connect startup to finish\");\n            }\n        }\n    }\n}\n", "numLines": 124, "startLine": 1, "totalLines": 124}}

